import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { RequestService } from '../../../../core/services/request.service';
import { SponsorshipRequest } from '../../../../core/models/request.model';

@Component({
  selector: 'app-request-detail',
  templateUrl: './request-detail.component.html',
  styleUrls: ['./request-detail.component.css']
})
export class RequestDetailComponent implements OnInit {
  requestId: number = 0;
  request: SponsorshipRequest | null = null;
  isLoading = false;
  isSubmitting = false;

  constructor(
    private route: ActivatedRoute,
    private requestService: RequestService,
    private router: Router
  ) {}

  ngOnInit() {
    this.requestId = Number(this.route.snapshot.paramMap.get('id'));
    this.loadRequestDetails();
  }

  loadRequestDetails() {
    this.isLoading = true;
    this.requestService.getRequestById(this.requestId).subscribe({
      next: (request) => {
        this.request = new SponsorshipRequest(request);
        this.isLoading = false;
      },
      error: (error) => {
        console.error('Error:', error);
        this.isLoading = false;
        alert('Error loading request details');
      }
    });
  }

  // Submit button - Only enabled for Draft status
  canSubmit(): boolean {
    return this.request?.status === 'Draft';
  }

  onSubmit() {
    if (!this.canSubmit()) {
      alert('Only draft requests can be submitted');
      return;
    }

    if (confirm('Are you sure you want to submit this request for approval?')) {
      this.isSubmitting = true;
      this.requestService.submitRequest(this.requestId).subscribe({
        next: () => {
          this.isSubmitting = false;
          alert('Request submitted successfully!');
          this.router.navigate(['/requestor/my-requests']);
        },
        error: (error) => {
          this.isSubmitting = false;
          alert(error.error?.message || 'Error submitting request');
        }
      });
    }
  }

  goBack() {
    this.router.navigate(['/requestor/my-requests']);
  }
}
<div class="container mt-4">
  <div class="card" *ngIf="!isLoading && request">
    <div class="card-header">
      <h3>Request Details</h3>
      <span class="badge" [class]="request.getStatusClass()">
        {{ request.getStatusText() }}
      </span>
    </div>

    <div class="card-body">
      <div class="row">
        <div class="col-md-6">
          <p><strong>Title:</strong> {{ request.title }}</p>
          <p><strong>Department:</strong> {{ request.department }}</p>
          <p><strong>Event Name:</strong> {{ request.eventName }}</p>
          <p><strong>Event Date:</strong> {{ request.eventDate | date }}</p>
        </div>
        <div class="col-md-6">
          <p><strong>Amount:</strong> ${{ request.requestedAmount }}</p>
          <p><strong>Status:</strong> {{ request.getStatusText() }}</p>
          <p><strong>Created:</strong> {{ request.createdAt | date }}</p>
        </div>
      </div>

      <div class="row mt-3">
        <div class="col-12">
          <p><strong>Justification:</strong></p>
          <p>{{ request.justification }}</p>
        </div>
      </div>
    </div>

    <div class="card-footer">
      <button class="btn btn-secondary" (click)="goBack()">Back</button>

      <!-- Submit button - Only enabled for Draft status -->
      <button class="btn btn-primary"
              (click)="onSubmit()"
              [disabled]="!canSubmit() || isSubmitting">
        <i *ngIf="isSubmitting" class="fas fa-spinner fa-spin"></i>
        {{ isSubmitting ? 'Submitting...' : 'Submit Request' }}
      </button>
    </div>
  </div>
</div>
